insert into public.quotes (id, category_id, position_in_category, text, author)
values
  ('s1', 'stoic', 1, 'You have power over your mind, not outside events. Realize this, and you will find strength.', 'Marcus Aurelius'),
  ('s2', 'stoic', 2, 'The impediment to action advances action. What stands in the way becomes the way.', 'Marcus Aurelius'),
  ('s3', 'stoic', 3, 'He who fears death will never do anything worthy of a man who is alive.', 'Seneca'),
  ('s4', 'stoic', 4, 'Waste no more time arguing about what a good man should be. Be one.', 'Marcus Aurelius'),
  ('s5', 'stoic', 5, 'It is not death that a man should fear, but he should fear never beginning to live.', 'Marcus Aurelius'),
  ('s6', 'stoic', 6, 'We suffer more in imagination than in reality.', 'Seneca'),
  ('s7', 'stoic', 7, 'The first rule is to keep an untroubled spirit. The second is to look things in the face and know them for what they are.', 'Marcus Aurelius'),
  ('s8', 'stoic', 8, 'Wherever there is a human being, there is an opportunity for a kindness.', 'Seneca'),
  ('s9', 'stoic', 9, 'No man is free who is not master of himself.', 'Epictetus'),
  ('s10', 'stoic', 10, 'Make the best use of what is in your power, and take the rest as it happens.', 'Epictetus'),
  ('s11', 'stoic', 11, 'Man is not disturbed by events, but by the opinions he has about events.', 'Epictetus'),
  ('s12', 'stoic', 12, 'Be tolerant with others and strict with yourself.', 'Marcus Aurelius'),
  ('s13', 'stoic', 13, 'How long are you going to wait before you demand the best for yourself?', 'Epictetus'),
  ('s14', 'stoic', 14, 'External things are not the problem. It is your assessment of them. Which you can revoke at any moment.', 'Marcus Aurelius'),
  ('s15', 'stoic', 15, 'Wealth consists not in having great possessions, but in having few wants.', 'Epictetus'),
  ('s16', 'stoic', 16, 'It never ceases to amaze me: we all love ourselves more than other people, but care more about their opinions than our own.', 'Marcus Aurelius'),
  ('s17', 'stoic', 17, 'The obstacle is the path.', 'Zen proverb (often attributed to Stoic tradition)'),
  ('s18', 'stoic', 18, 'Nothing is so bitter that a calm mind cannot find comfort in it.', 'Seneca'),
  ('s19', 'stoic', 19, 'Seek not the good in external things; seek it in yourself.', 'Epictetus'),
  ('s20', 'stoic', 20, 'What is defeat? Nothing but education; nothing but the first step toward something better.', 'Wendell Phillips (in Stoic tradition)'),
  ('s21', 'stoic', 21, 'Begin at once to live, and count each separate day as a separate life.', 'Seneca'),
  ('s22', 'stoic', 22, 'A gem cannot be polished without friction, nor a man perfected without trials.', 'Seneca'),
  ('s23', 'stoic', 23, 'Receive without pride, abandon without struggle.', 'Marcus Aurelius'),
  ('s24', 'stoic', 24, 'It is not the man who has too little that is poor, but the one who hankers after more.', 'Seneca'),
  ('s25', 'stoic', 25, 'To bear trials with a calm mind robs misfortune of its strength and burden.', 'Seneca'),
  ('s26', 'stoic', 26, 'Think of yourself as dead. You have lived your life. Now take what''s left and live it properly.', 'Marcus Aurelius'),
  ('s27', 'stoic', 27, 'No great thing is created suddenly.', 'Epictetus'),
  ('s28', 'stoic', 28, 'If it is not right, do not do it; if it is not true, do not say it.', 'Marcus Aurelius'),
  ('s29', 'stoic', 29, 'The more we value things outside our control, the less control we have.', 'Epictetus'),
  ('s30', 'stoic', 30, 'Difficulties are things that show a person what they are.', 'Epictetus'),
  ('s31', 'stoic', 31, 'He suffers more than necessary, who suffers before it is necessary.', 'Seneca'),
  ('s32', 'stoic', 32, 'The whole future lies in uncertainty: live immediately.', 'Seneca'),
  ('s33', 'stoic', 33, 'If someone is able to show me that what I think or do is not right, I will happily change.', 'Marcus Aurelius'),
  ('s34', 'stoic', 34, 'True happiness is to enjoy the present, without anxious dependence upon the future.', 'Seneca'),
  ('s35', 'stoic', 35, 'When you wake up in the morning, tell yourself: the people I deal with today will be meddling, ungrateful, arrogant, dishonest, jealous and surly.', 'Marcus Aurelius'),
  ('s36', 'stoic', 36, 'Associate with those who will make a better man of you.', 'Seneca'),
  ('s37', 'stoic', 37, 'Give yourself a gift: the present moment.', 'Marcus Aurelius'),
  ('s38', 'stoic', 38, 'Confine yourself to the present.', 'Marcus Aurelius'),
  ('s39', 'stoic', 39, 'Do not dwell on the past, nor dream too much of the future, but concentrate the mind on the present moment.', 'Stoic tradition'),
  ('s40', 'stoic', 40, 'He who has a why to live can bear almost any how.', 'Friedrich Nietzsche (Stoic-aligned)'),
  ('s41', 'stoic', 41, 'Loss is nothing else but change, and change is Nature''s delight.', 'Marcus Aurelius'),
  ('s42', 'stoic', 42, 'Not what we have but what we enjoy constitutes our abundance.', 'Epicurus'),
  ('s43', 'stoic', 43, 'Never esteem anything as of advantage to you that will make you break your word or lose your self-respect.', 'Marcus Aurelius'),
  ('s44', 'stoic', 44, 'Silence is a lesson learned through life''s many sufferings.', 'Seneca'),
  ('s45', 'stoic', 45, 'The brave man is not he who does not feel afraid, but he who conquers that fear.', 'Nelson Mandela (Stoic tradition)'),
  ('s46', 'stoic', 46, 'Our life is what our thoughts make it.', 'Marcus Aurelius'),
  ('s47', 'stoic', 47, 'I have often wondered how it is that every man loves himself more than all the rest of men, but yet sets less value on his own opinions of himself than on the opinions of others.', 'Marcus Aurelius'),
  ('s48', 'stoic', 48, 'The soul that sees beauty may sometimes walk alone.', 'Johann Wolfgang von Goethe'),
  ('s49', 'stoic', 49, 'Progress is not achieved by luck or accident, but by working on yourself daily.', 'Epictetus'),
  ('s50', 'stoic', 50, 'First say to yourself what you would be; then do what you have to do.', 'Epictetus'),
  ('s51', 'stoic', 51, 'You become what you give your attention to.', 'Epictetus'),
  ('s52', 'stoic', 52, 'The happy life is one in harmony with its own nature.', 'Seneca'),
  ('s53', 'stoic', 53, 'Nothing, to my way of thinking, is a better proof of a well ordered mind than a man''s ability to stop just where he is and pass some time in his own company.', 'Seneca'),
  ('s54', 'stoic', 54, 'Retire into yourself as much as you can.', 'Seneca'),
  ('s55', 'stoic', 55, 'People are not disturbed by things, but by the view they take of them.', 'Epictetus'),
  ('s56', 'stoic', 56, 'Be content to seem what you really are.', 'Marcus Aurelius'),
  ('s57', 'stoic', 57, 'Caretake this moment. Immerse yourself in its particulars.', 'Epictetus'),
  ('s58', 'stoic', 58, 'Know first who you are, and then adorn yourself accordingly.', 'Epictetus'),
  ('s59', 'stoic', 59, 'Do not be ashamed of your mistakes but rather learn from them.', 'Confucius (Stoic parallel)'),
  ('s60', 'stoic', 60, 'Don''t explain your philosophy. Embody it.', 'Epictetus'),
  ('s61', 'stoic', 61, 'Accept the things to which fate binds you, and love the people with whom fate brings you together, and do so with all your heart.', 'Marcus Aurelius'),
  ('s62', 'stoic', 62, 'The obstacle in the path becomes the path. Never forget, within every obstacle is an opportunity to improve our condition.', 'Ryan Holiday'),
  ('s63', 'stoic', 63, 'Memento mori — remember that you will die.', 'Stoic tradition'),
  ('s64', 'stoic', 64, 'Amor fati — love your fate.', 'Nietzsche (Stoic-aligned)'),
  ('s65', 'stoic', 65, 'To live is the rarest thing in the world. Most people exist, that is all.', 'Oscar Wilde'),
  ('s66', 'stoic', 66, 'When you arise in the morning, think of what a privilege it is to be alive, to think, to enjoy, to love.', 'Marcus Aurelius'),
  ('s67', 'stoic', 67, 'The purpose of life is not to be happy. It is to be useful, to be honorable, to be compassionate.', 'Ralph Waldo Emerson'),
  ('s68', 'stoic', 68, 'Very little is needed to make a happy life; it is all within yourself, in your way of thinking.', 'Marcus Aurelius'),
  ('s69', 'stoic', 69, 'Almost nothing material is needed for a happy life, for he who has understood existence.', 'Marcus Aurelius'),
  ('s70', 'stoic', 70, 'Whoever does not regard what he has as most ample wealth, is unhappy, though he be master of the world.', 'Epictetus'),
  ('s71', 'stoic', 71, 'Do not go on discussing what a good person should be. Just be one.', 'Marcus Aurelius'),
  ('s72', 'stoic', 72, 'The tranquility that comes when you stop caring what they say. Or think, or do. Only what you do.', 'Marcus Aurelius'),
  ('s73', 'stoic', 73, 'The soul becomes dyed with the color of its thoughts.', 'Marcus Aurelius'),
  ('s74', 'stoic', 74, 'Dwell on the beauty of life. Watch the stars, and see yourself running with them.', 'Marcus Aurelius'),
  ('s75', 'stoic', 75, 'All is ephemeral — fame and the famous as well.', 'Marcus Aurelius'),
  ('s76', 'stoic', 76, 'You have power over your mind — not outside events. Realize this and you will find strength.', 'Marcus Aurelius'),
  ('s77', 'stoic', 77, 'Perfection of character is this: to live each day as if it were your last, without frenzy, without apathy, without pretense.', 'Marcus Aurelius'),
  ('s78', 'stoic', 78, 'When you wake up in the morning, ask yourself: What is there in me that is still free?', 'Epictetus'),
  ('s79', 'stoic', 79, 'People are disturbed, not by things, but by the principles and notions which they form concerning things.', 'Epictetus'),
  ('s80', 'stoic', 80, 'Freedom is the only worthy goal in life. It is won by disregarding things that lie beyond our control.', 'Epictetus'),
  ('s81', 'stoic', 81, 'To make the best of what is in our power, and take the rest as it naturally happens.', 'Epictetus'),
  ('s82', 'stoic', 82, 'Seek not that the things which happen should happen as you wish; but wish the things which happen to be as they are, and you will have a tranquil flow of life.', 'Epictetus'),
  ('s83', 'stoic', 83, 'Neither seek nor shun, but what is past is past.', 'Seneca'),
  ('s84', 'stoic', 84, 'Tomorrow I shall be cleverer.', 'Seneca'),
  ('s85', 'stoic', 85, 'It is not because things are difficult that we do not dare; it is because we do not dare that things are difficult.', 'Seneca'),
  ('s86', 'stoic', 86, 'If you wish to be a writer, write.', 'Epictetus'),
  ('s87', 'stoic', 87, 'The greatest weapon against stress is our ability to choose one thought over another.', 'William James (Stoic tradition)'),
  ('s88', 'stoic', 88, 'Disregard the obstacles. Obstacles are placed in our path for us to overcome them.', 'Seneca'),
  ('s89', 'stoic', 89, 'A good character is the only guarantee of everlasting carefree happiness.', 'Seneca'),
  ('s90', 'stoic', 90, 'Choose not to be harmed — and you won''t feel harmed. Don''t feel harmed — and you haven''t been.', 'Marcus Aurelius'),
  ('s91', 'stoic', 91, 'God, grant me the serenity to accept the things I cannot change, courage to change the things I can, and wisdom to know the difference.', 'Reinhold Niebuhr (Stoic-aligned)'),
  ('s92', 'stoic', 92, 'It is the power of the mind to be unconquerable.', 'Seneca'),
  ('s93', 'stoic', 93, 'The wise man is never less alone than when he is alone.', 'Cicero'),
  ('s94', 'stoic', 94, 'How much time he saves who does not look to see what his neighbor says or does or thinks.', 'Marcus Aurelius'),
  ('s95', 'stoic', 95, 'The first step: Don''t be anxious. Nature controls it all.', 'Marcus Aurelius'),
  ('s96', 'stoic', 96, 'So you must match time''s swiftness with your speed in using it, and you must drink quickly as though from a rapid stream that will not always flow.', 'Seneca'),
  ('s97', 'stoic', 97, 'Timendi causa est nescire — Ignorance is the cause of fear.', 'Seneca'),
  ('s98', 'stoic', 98, 'For it is not death or pain that is to be feared, but the fear of pain or death.', 'Epictetus'),
  ('s99', 'stoic', 99, 'He is a man of sense who does not grieve for what he has not, but rejoices in what he has.', 'Epictetus'),
  ('s100', 'stoic', 100, 'Do not spoil what you have by desiring what you have not.', 'Epicurus'),
  ('s101', 'stoic', 101, 'Just keep in mind: the more we value things outside our control, the less control we have.', 'Epictetus'),
  ('s102', 'stoic', 102, 'Today I escaped anxiety. Or no, I discarded it, because it was within me, in my own perceptions — not outside.', 'Marcus Aurelius'),
  ('s103', 'stoic', 103, 'The first and greatest victory is to conquer yourself.', 'Plato'),
  ('s104', 'stoic', 104, 'It''s time you realized that you have something in you more powerful and miraculous than the things that affect you.', 'Marcus Aurelius'),
  ('s105', 'stoic', 105, 'Never let the future disturb you. You will meet it, if you have to, with the same weapons of reason which today arm you against the present.', 'Marcus Aurelius'),
  ('s106', 'stoic', 106, 'Ask yourself at every moment, ''Is this necessary?''', 'Marcus Aurelius'),
  ('s107', 'stoic', 107, 'Your time is limited, so don''t waste it living someone else''s life.', 'Steve Jobs (Stoic-aligned)'),
  ('s108', 'stoic', 108, 'Be like the cliff against which the waves continually break; but it stands firm and tames the fury of the water around it.', 'Marcus Aurelius'),
  ('s109', 'stoic', 109, 'Never esteem anything as of advantage if it will make you break your word.', 'Marcus Aurelius'),
  ('s110', 'stoic', 110, 'You don''t develop courage by being happy in your relationships every day. You develop it by surviving difficult times and challenging adversity.', 'Epicurus'),
  ('s111', 'stoic', 111, 'The impediment to action advances action.', 'Marcus Aurelius'),
  ('s112', 'stoic', 112, 'I am not afraid of tomorrow, for I have seen yesterday and I love today.', 'William Allen White'),
  ('s113', 'stoic', 113, 'Practice yourself, for heaven''s sake, in little things; and thence proceed to greater.', 'Epictetus'),
  ('s114', 'stoic', 114, 'Attach yourself to what is spiritually superior, regardless of what other people think or do.', 'Epictetus'),
  ('s115', 'stoic', 115, 'In prosperity, it is very easy to find a friend; in adversity, nothing is so difficult.', 'Epictetus'),
  ('s116', 'stoic', 116, 'If you are pained by any external thing, it is not this thing that disturbs you, but your own judgment about it.', 'Marcus Aurelius'),
  ('s117', 'stoic', 117, 'Begin; to have commenced is half the deed.', 'Ausonius (Stoic tradition)'),
  ('s118', 'stoic', 118, 'Nothing has such power to broaden the mind as the ability to investigate systematically and truly all that comes under thy observation in life.', 'Marcus Aurelius'),
  ('s119', 'stoic', 119, 'The first rule is to keep an untroubled spirit.', 'Marcus Aurelius'),
  ('s120', 'stoic', 120, 'Order your soul. Reduce your wants. Live in charity. Associate in Christian community.', 'Augustine (Stoic-aligned)'),
  ('s121', 'stoic', 121, 'Equanimity is the hallmark of spiritual maturity.', 'Stoic tradition'),
  ('s122', 'stoic', 122, 'Expect nothing. Be prepared for everything.', 'Seneca'),
  ('s123', 'stoic', 123, 'Self-discipline begins with the mastery of your thoughts.', 'Napoleon Hill (Stoic tradition)'),
  ('s124', 'stoic', 124, 'It is the mark of an educated mind to be able to entertain a thought without accepting it.', 'Aristotle'),
  ('s125', 'stoic', 125, 'Reason does not work instinctively, but requires trial, practice, and instruction in order to gradually progress from one level of insight to another.', 'Immanuel Kant'),
  ('s126', 'stoic', 126, 'In all things of nature there is something of the marvelous.', 'Aristotle'),
  ('s127', 'stoic', 127, 'Courage is not simply one of the virtues, but the form of every virtue at the testing point.', 'C.S. Lewis (Stoic-aligned)'),
  ('s128', 'stoic', 128, 'The more you know, the more you know you don''t know.', 'Aristotle'),
  ('s129', 'stoic', 129, 'To be evenminded is the greatest virtue.', 'Heraclitus'),
  ('s130', 'stoic', 130, 'Everything can be taken from a man but one thing: the last of the human freedoms — to choose one''s attitude.', 'Viktor Frankl'),
  ('s131', 'stoic', 131, 'Between stimulus and response there is a space. In that space is our power to choose our response.', 'Viktor Frankl'),
  ('s132', 'stoic', 132, 'Character is destiny.', 'Heraclitus'),
  ('s133', 'stoic', 133, 'Out of your vulnerabilities will come your strength.', 'Sigmund Freud (Stoic tradition)'),
  ('s134', 'stoic', 134, 'Endure, and preserve yourself for better times.', 'Virgil'),
  ('s135', 'stoic', 135, 'Virtue does not come from wealth, but wealth, and every other good thing which men have, comes from virtue.', 'Socrates'),
  ('s136', 'stoic', 136, 'The greatest remedy for anger is delay.', 'Seneca'),
  ('s137', 'stoic', 137, 'Wherever there is life, there is hope.', 'Terence'),
  ('s138', 'stoic', 138, 'I judge a man by his questions rather than his answers.', 'Voltaire (Stoic tradition)'),
  ('s139', 'stoic', 139, 'Respond; don''t react. Listen; don''t talk. Think; don''t assume.', 'Raji Lukkoor'),
  ('s140', 'stoic', 140, 'A man who cannot be silenced by any argument is not a man of reason.', 'Marcus Aurelius (paraphrased)'),
  ('s141', 'stoic', 141, 'Not to be taken aback by anything that happens.', 'Seneca'),
  ('s142', 'stoic', 142, 'Never hurry and never cease.', 'Goethe (Stoic tradition)'),
  ('s143', 'stoic', 143, 'Act well at the moment.', 'Proverb'),
  ('s144', 'stoic', 144, 'In difficulties, I will always maintain my equanimity.', 'Epictetus'),
  ('s145', 'stoic', 145, 'Seek to understand before you seek to be understood.', 'Stephen Covey (Stoic tradition)'),
  ('s146', 'stoic', 146, 'Before you act, listen. Before you react, think. Before you spend, earn. Before you criticize, wait.', 'Ernest Hemingway (attributed)'),
  ('s147', 'stoic', 147, 'Silence is the sleep that nourishes wisdom.', 'Francis Bacon'),
  ('s148', 'stoic', 148, 'The unexamined life is not worth living.', 'Socrates'),
  ('s149', 'stoic', 149, 'He who is brave is free.', 'Seneca'),
  ('s150', 'stoic', 150, 'All the darkness in the world cannot extinguish the light of a single candle.', 'Francis of Assisi (Stoic-aligned)'),
  ('s151', 'stoic', 151, 'Let all your things have their places; let each part of your business have its time.', 'Benjamin Franklin (Stoic-aligned)'),
  ('s152', 'stoic', 152, 'He is richest who is content with the least.', 'Socrates'),
  ('s153', 'stoic', 153, 'Most powerful is he who has himself in his own power.', 'Seneca'),
  ('s154', 'stoic', 154, 'A man is as miserable as he thinks he is.', 'Seneca'),
  ('s155', 'stoic', 155, 'He is a wise man who does not grieve for the things which he has not, but rejoices for those which he has.', 'Epictetus'),
  ('s156', 'stoic', 156, 'One must always be careful of boredom, for it is the source of all trouble.', 'Stoic tradition'),
  ('s157', 'stoic', 157, 'Small deeds done are better than great deeds planned.', 'Peter Marshall (Stoic-aligned)'),
  ('s158', 'stoic', 158, 'Even if you were to live three thousand years, or thirty thousand, remember that no one loses any other life than the one he is living.', 'Marcus Aurelius'),
  ('s159', 'stoic', 159, 'Receive without pride, abandon without struggle. What has ripened must fall.', 'Marcus Aurelius'),
  ('s160', 'stoic', 160, 'The happiness of your life depends upon the quality of your thoughts.', 'Marcus Aurelius'),
  ('s161', 'stoic', 161, 'Everything we hear is an opinion, not a fact. Everything we see is a perspective, not the truth.', 'Marcus Aurelius'),
  ('s162', 'stoic', 162, 'If anyone tells you that a certain person speaks ill of you, do not make excuses about what is said of you but answer, He did not know all my other faults.', 'Epictetus'),
  ('s163', 'stoic', 163, 'Nusquam est qui ubique est — He who is everywhere is nowhere.', 'Seneca'),
  ('s164', 'stoic', 164, 'Let philosophy scrape off your own faults, rather than be a way to rail against the faults of others.', 'Seneca'),
  ('s165', 'stoic', 165, 'I have always thought the actions of men the best interpreters of their thoughts.', 'John Locke'),
  ('s166', 'stoic', 166, 'The day is wasted on which one has not laughed.', 'Nicolas Chamfort'),
  ('s167', 'stoic', 167, 'The key to being undisturbed is not caring what others think of you.', 'Epictetus (paraphrased)'),
  ('s168', 'stoic', 168, 'To be uncertain is to be uncomfortable, but to be certain is to be ridiculous.', 'Chinese proverb (Stoic parallel)'),
  ('s169', 'stoic', 169, 'Adversity has the effect of eliciting talents which in prosperous circumstances would have lain dormant.', 'Horace'),
  ('s170', 'stoic', 170, 'We can easily forgive a child who is afraid of the dark; the real tragedy of life is when men are afraid of the light.', 'Plato'),
  ('s171', 'stoic', 171, 'Fire tests gold, suffering tests brave men.', 'Seneca'),
  ('s172', 'stoic', 172, 'The bravest sight in the world is to see a great man struggling against adversity.', 'Seneca'),
  ('s173', 'stoic', 173, 'He who is of calm and happy nature will hardly feel the pressure of age, but to him who is of an opposite disposition, youth and age are equally a burden.', 'Plato'),
  ('s174', 'stoic', 174, 'Waste no more time arguing about what a good man should be.', 'Marcus Aurelius'),
  ('s175', 'stoic', 175, 'You are an actor in a play, the character of which has been determined by the Author: short, if He wants it short; long, if He wants it long.', 'Epictetus'),
  ('s176', 'stoic', 176, 'If you would be a real seeker after truth, it is necessary that at least once in your life you doubt, as far as possible, all things.', 'Descartes (Stoic tradition)'),
  ('s177', 'stoic', 177, 'You could leave life right now. Let that determine what you do and say and think.', 'Marcus Aurelius'),
  ('s178', 'stoic', 178, 'The things you own end up owning you.', 'Fight Club (Stoic-aligned)'),
  ('s179', 'stoic', 179, 'To be content with what we possess is the greatest and most secure of riches.', 'Cicero'),
  ('s180', 'stoic', 180, 'Wherever there is a human being, there is an opportunity for kindness.', 'Seneca'),
  ('s181', 'stoic', 181, 'He suffers more than necessary who suffers before it is necessary.', 'Seneca'),
  ('s182', 'stoic', 182, 'Fate leads the willing and drags along the reluctant.', 'Seneca'),
  ('s183', 'stoic', 183, 'Do every act of your life as though it were the last act of your life.', 'Marcus Aurelius'),
  ('s184', 'stoic', 184, 'Courage consists not in blindly overlooking danger, but in seeing it, and conquering it.', 'Jean Paul'),
  ('s185', 'stoic', 185, 'It is the quality of the mind that gives greatness to the work.', 'Seneca'),
  ('s186', 'stoic', 186, 'You must expect to be treated roughly by the world, and brace yourself.', 'Seneca (paraphrased)'),
  ('s187', 'stoic', 187, 'A man who dares to waste one hour of time has not discovered the value of life.', 'Charles Darwin (Stoic-aligned)'),
  ('s188', 'stoic', 188, 'Do not act as if you had ten thousand years to live.', 'Marcus Aurelius'),
  ('s189', 'stoic', 189, 'Knowledge which is acquired under compulsion obtains no hold on the mind.', 'Plato'),
  ('s190', 'stoic', 190, 'It is not the man who has little who is poor, but the one who craves more.', 'Seneca'),
  ('s191', 'stoic', 191, 'Think not of yourself as the author of your fortunes, but as their careful steward.', 'Stoic tradition'),
  ('s192', 'stoic', 192, 'If not me, who? If not now, when?', 'Hillel the Elder'),
  ('s193', 'stoic', 193, 'Look well into thyself; there is a source of strength which will always spring up if thou wilt always look.', 'Marcus Aurelius'),
  ('s194', 'stoic', 194, 'Nothing great in the world was accomplished without passion.', 'Hegel (Stoic-aligned)'),
  ('s195', 'stoic', 195, 'Logic will get you from A to B. Imagination will take you everywhere.', 'Albert Einstein'),
  ('s196', 'stoic', 196, 'The two most important days in your life are the day you are born and the day you find out why.', 'Mark Twain (Stoic-aligned)'),
  ('s197', 'stoic', 197, 'Educating the mind without educating the heart is no education at all.', 'Aristotle'),
  ('s198', 'stoic', 198, 'He that would govern others, first should be master of himself.', 'Philip Massinger'),
  ('s199', 'stoic', 199, 'Patience and time do more than strength or passion.', 'Jean de La Fontaine'),
  ('s200', 'stoic', 200, 'Do not be too timid and squeamish about your actions. All life is an experiment.', 'Ralph Waldo Emerson'),
  ('c1', 'self-compassion', 1, 'You yourself, as much as anybody in the entire universe, deserve your love and affection.', 'Buddha'),
  ('c2', 'self-compassion', 2, 'Talk to yourself like you would talk to someone you love.', 'Brené Brown'),
  ('c3', 'self-compassion', 3, 'Be gentle with yourself. You are a child of the universe, no less than the trees and the stars.', 'Max Ehrmann'),
  ('c4', 'self-compassion', 4, 'You are enough. A thousand times enough.', 'Atticus'),
  ('c5', 'self-compassion', 5, 'To love oneself is the beginning of a lifelong romance.', 'Oscar Wilde'),
  ('c6', 'self-compassion', 6, 'Self-compassion is simply giving the same kindness to ourselves that we would give to others.', 'Christopher Germer'),
  ('c7', 'self-compassion', 7, 'Owning our story and loving ourselves through that process is the bravest thing we will ever do.', 'Brené Brown'),
  ('c8', 'self-compassion', 8, 'Be kind to yourself so you can be happy enough to be kind to the world.', 'Misha Collins'),
  ('c9', 'self-compassion', 9, 'You can''t pour from an empty cup. Take care of yourself first.', 'Unknown'),
  ('c10', 'self-compassion', 10, 'I am not what happened to me, I am what I choose to become.', 'Carl Jung'),
  ('c11', 'self-compassion', 11, 'Love yourself first and everything else falls into line.', 'Lucille Ball'),
  ('c12', 'self-compassion', 12, 'Self-care is not self-indulgence, it is self-preservation.', 'Audre Lorde'),
  ('c13', 'self-compassion', 13, 'It''s not your job to be everything to everyone.', 'Unknown'),
  ('c14', 'self-compassion', 14, 'To be yourself in a world that is constantly trying to make you something else is the greatest accomplishment.', 'Ralph Waldo Emerson'),
  ('c15', 'self-compassion', 15, 'You are allowed to be both a masterpiece and a work in progress simultaneously.', 'Sophia Bush'),
  ('c16', 'self-compassion', 16, 'Give yourself the same compassion you would give a good friend.', 'Unknown'),
  ('c17', 'self-compassion', 17, 'Rest if you must, but don''t you quit.', 'Edgar A. Guest'),
  ('c18', 'self-compassion', 18, 'You are not required to set yourself on fire to keep others warm.', 'Unknown'),
  ('c19', 'self-compassion', 19, 'You are worthy of love. Especially from yourself.', 'Unknown'),
  ('c20', 'self-compassion', 20, 'The most powerful relationship you will ever have is the relationship with yourself.', 'Steve Maraboli'),
  ('c21', 'self-compassion', 21, 'Nourishing yourself in a way that helps you blossom in the direction you want to go is attainable.', 'Deborah Day'),
  ('c22', 'self-compassion', 22, 'It''s okay to be a glowstick. Sometimes we need to break before we shine.', 'Unknown'),
  ('c23', 'self-compassion', 23, 'Nothing can dim the light that shines from within.', 'Maya Angelou'),
  ('c24', 'self-compassion', 24, 'I am learning every day to allow the space between where I am and where I want to be to inspire me and not terrify me.', 'Tracee Ellis Ross'),
  ('c25', 'self-compassion', 25, 'There is nothing enlightened about shrinking so that other people won''t feel insecure around you.', 'Marianne Williamson'),
  ('c26', 'self-compassion', 26, 'Accept yourself, love yourself, and keep moving forward.', 'Roy T. Bennett'),
  ('c27', 'self-compassion', 27, 'Forgiveness is giving up the hope that the past could have been any different.', 'Oprah Winfrey'),
  ('c28', 'self-compassion', 28, 'Be patient with yourself. Self-growth is tender; it''s holy ground.', 'Stephen Covey'),
  ('c29', 'self-compassion', 29, 'To forgive is to set a prisoner free and discover the prisoner was you.', 'Lewis B. Smedes'),
  ('c30', 'self-compassion', 30, 'Imperfections are not inadequacies; they are reminders that we''re all in this together.', 'Brené Brown'),
  ('c31', 'self-compassion', 31, 'It''s not who you are that holds you back, it''s who you think you''re not.', 'Denis Waitley'),
  ('c32', 'self-compassion', 32, 'The fact that you''re struggling doesn''t make you a burden. It makes you human.', 'Unknown'),
  ('c33', 'self-compassion', 33, 'No one can make you feel inferior without your consent.', 'Eleanor Roosevelt'),
  ('c34', 'self-compassion', 34, 'You are braver than you believe, stronger than you seem, and smarter than you think.', 'A.A. Milne'),
  ('c35', 'self-compassion', 35, 'You don''t have to be positive all the time. It''s perfectly okay to feel sad, angry, annoyed, frustrated, scared, or anxious.', 'Lori Deschene'),
  ('c36', 'self-compassion', 36, 'Be enough for yourself first. The rest of the world can wait.', 'Unknown'),
  ('c37', 'self-compassion', 37, 'You deserve to be the protagonist of your own beautiful, sometimes-messy life.', 'Nora Ephron (paraphrased)'),
  ('c38', 'self-compassion', 38, 'Healing doesn''t mean the damage never existed. It means the damage no longer controls our lives.', 'Akshay Dubey'),
  ('c39', 'self-compassion', 39, 'The privilege of a lifetime is to become who you truly are.', 'Carl Jung'),
  ('c40', 'self-compassion', 40, 'With everything that has happened to you, you can either feel sorry for yourself or treat what has happened as a gift.', 'Wayne Dyer'),
  ('c41', 'self-compassion', 41, 'What if you simply devoted this year to loving yourself more?', 'Unknown'),
  ('c42', 'self-compassion', 42, 'There is no exercise better for the heart than reaching down and lifting people up.', 'John Holmes (self-compassion tradition)'),
  ('c43', 'self-compassion', 43, 'You are valuable because you exist. Not because of what you do or what you have done, but simply because you are.', 'Max Lucado'),
  ('c44', 'self-compassion', 44, 'Compassion for others begins with kindness to ourselves.', 'Pema Chödrön'),
  ('c45', 'self-compassion', 45, 'You can''t hate yourself happy. You can''t criticize yourself thin. You can''t shame yourself into being worthy. Real change begins with self-compassion.', 'Lori Deschene'),
  ('c46', 'self-compassion', 46, 'Suffering is a call for inquiry, not a call for self-pity.', 'Byron Katie'),
  ('c47', 'self-compassion', 47, 'Do not judge your emotions. Simply notice them.', 'Kristin Neff'),
  ('c48', 'self-compassion', 48, 'One of the most courageous things you can do is identify yourself, know who you are, what you believe in and where you want to go.', 'Sheila Murray Bethel'),
  ('c49', 'self-compassion', 49, 'The more you know yourself, the more clarity there is. Self-knowledge has no end.', 'Jiddu Krishnamurti'),
  ('c50', 'self-compassion', 50, 'It is not the mountain we conquer, but ourselves.', 'Sir Edmund Hillary'),
  ('c51', 'self-compassion', 51, 'You are worthy of a love you don''t have to earn.', 'Unknown'),
  ('c52', 'self-compassion', 52, 'Stop shrinking yourself to fit places you''ve outgrown.', 'Unknown'),
  ('c53', 'self-compassion', 53, 'The most loving thing you can do for others is to take care of yourself.', 'Unknown'),
  ('c54', 'self-compassion', 54, 'We need much less than we think we need.', 'Maya Angelou'),
  ('c55', 'self-compassion', 55, 'Self-compassion is the antidote to shame.', 'Brené Brown'),
  ('c56', 'self-compassion', 56, 'Be soft. Do not let the world make you hard. Do not let pain make you hate.', 'Iain Thomas'),
  ('c57', 'self-compassion', 57, 'You are not a problem to be solved.', 'Glennon Doyle'),
  ('c58', 'self-compassion', 58, 'It''s okay to not be okay — as long as you are not giving up.', 'Karen Salmansohn'),
  ('c59', 'self-compassion', 59, 'Give yourself permission to immediately walk away from anything that gives you bad vibes.', 'Unknown'),
  ('c60', 'self-compassion', 60, 'What you think, you become. What you feel, you attract. What you imagine, you create.', 'Buddha'),
  ('c61', 'self-compassion', 61, 'I am not afraid of storms, for I am learning how to sail my ship.', 'Louisa May Alcott'),
  ('c62', 'self-compassion', 62, 'Feeling deeply is not a weakness. It is a profound form of strength.', 'Unknown'),
  ('c63', 'self-compassion', 63, 'You''ve been criticizing yourself for years and it hasn''t worked. Try approving of yourself and see what happens.', 'Louise L. Hay'),
  ('c64', 'self-compassion', 64, 'You are not a burden. You are a human being with needs, and that is okay.', 'Unknown'),
  ('c65', 'self-compassion', 65, 'Loving yourself isn''t vanity. It''s sanity.', 'Katrina Mayer'),
  ('c66', 'self-compassion', 66, 'The most difficult thing is the decision to act. The rest is merely tenacity.', 'Amelia Earhart'),
  ('c67', 'self-compassion', 67, 'What we don''t need in the midst of struggle is shame for being human.', 'Brené Brown'),
  ('c68', 'self-compassion', 68, 'In order to love who you are, you cannot hate the experiences that shaped you.', 'Andrea Dykstra'),
  ('c69', 'self-compassion', 69, 'You yourself deserve your love as much as anyone else does.', 'Kristin Neff'),
  ('c70', 'self-compassion', 70, 'When you recover or discover something that nourishes your soul, care enough about yourself to make room for it in your life.', 'Jean Shinoda Bolen'),
  ('c71', 'self-compassion', 71, 'Self-love is asking yourself what you need — every day — and then making sure you receive it.', 'Unknown'),
  ('c72', 'self-compassion', 72, 'You are enough, right now, as you are.', 'Kristin Neff'),
  ('c73', 'self-compassion', 73, 'Don''t be so hard on yourself. The mom in ''E.T.'' had an alien living in her house for days and didn''t notice.', 'Conan O''Brien (lighthearted self-compassion)'),
  ('c74', 'self-compassion', 74, 'The inner critic is just a scared child who doesn''t know any better.', 'Unknown'),
  ('c75', 'self-compassion', 75, 'Healing is not linear.', 'Unknown'),
  ('c76', 'self-compassion', 76, 'Today you are you! That is truer than true! There is no one alive who is you-er than you!', 'Dr. Seuss'),
  ('c77', 'self-compassion', 77, 'Sometimes you need to step outside, get some air, and remind yourself of who you are and where you want to be.', 'Unknown'),
  ('c78', 'self-compassion', 78, 'Your past is just a story. And once you realize this, it has no power over you.', 'Chuck Palahniuk'),
  ('c79', 'self-compassion', 79, 'To love and win is the best thing. To love and lose, the next best.', 'William Makepeace Thackeray'),
  ('c80', 'self-compassion', 80, 'Growth and comfort do not coexist.', 'Ginni Rometty (self-compassion tradition)'),
  ('c81', 'self-compassion', 81, 'When I accept myself, I am freed from the burden of needing you to accept me.', 'Steve Maraboli'),
  ('c82', 'self-compassion', 82, 'Go easy on yourself. Whatever you do today, let it be enough.', 'Unknown'),
  ('c83', 'self-compassion', 83, 'Not until we are lost do we begin to understand ourselves.', 'Henry David Thoreau'),
  ('c84', 'self-compassion', 84, 'You were wild once. Don''t let them tame you.', 'Isadora Duncan'),
  ('c85', 'self-compassion', 85, 'Each step in self-discovery is a step toward freedom.', 'Unknown'),
  ('c86', 'self-compassion', 86, 'The way you treat yourself sets the standard for others.', 'Sonya Friedman'),
  ('c87', 'self-compassion', 87, 'Sometimes self-care is exercise and eating right. Sometimes it''s sleeping in and eating cake. You get to decide.', 'Unknown'),
  ('c88', 'self-compassion', 88, 'To be fully alive, fully human, and completely awake is to be continually thrown out of the nest.', 'Pema Chödrön'),
  ('c89', 'self-compassion', 89, 'You can''t save everyone. Sometimes you have to accept that you did your best with the person.', 'Dodinsky'),
  ('c90', 'self-compassion', 90, 'Who you are is not what happened to you.', 'Unknown'),
  ('c91', 'self-compassion', 91, 'Permission slips aren''t just for school. Sometimes you need to give yourself one.', 'Brené Brown'),
  ('c92', 'self-compassion', 92, 'The more you love your decisions, the less you need others to love them.', 'Unknown'),
  ('c93', 'self-compassion', 93, 'Empathy is the antidote to shame.', 'Brené Brown'),
  ('c94', 'self-compassion', 94, 'Do not let your wounds transform you into someone you are not.', 'Unknown'),
  ('c95', 'self-compassion', 95, 'Self-compassion means you are always protected.', 'Kristin Neff'),
  ('c96', 'self-compassion', 96, 'Boundaries are a form of self-respect.', 'Unknown'),
  ('c97', 'self-compassion', 97, 'Make peace with your past so it won''t disturb your present.', 'Paulo Coelho'),
  ('c98', 'self-compassion', 98, 'Take rest; a field that has rested gives a bountiful crop.', 'Ovid'),
  ('c99', 'self-compassion', 99, 'You do not find the happy life. You make it.', 'Thomas S. Monson'),
  ('c100', 'self-compassion', 100, 'Give yourself permission to grow at your own pace.', 'Unknown'),
  ('c101', 'self-compassion', 101, 'Please be kind to everyone you meet, for we are all fighting hard battles.', 'Ian MacLaren'),
  ('c102', 'self-compassion', 102, 'To establish true self-esteem we must concentrate on our successes and forget about the failures and the negatives in our lives.', 'Denis Waitley'),
  ('c103', 'self-compassion', 103, 'Comparison is an act of violence against the self.', 'Iyanla Vanzant'),
  ('c104', 'self-compassion', 104, 'When you are in your own company, be the best friend you''ve ever had.', 'Unknown'),
  ('c105', 'self-compassion', 105, 'Let yourself be human.', 'Unknown'),
  ('c106', 'self-compassion', 106, 'No matter what your history has been, your destiny is what you create today.', 'Steve Maraboli'),
  ('c107', 'self-compassion', 107, 'You can''t go back and change the beginning, but you can start where you are and change the ending.', 'C.S. Lewis'),
  ('c108', 'self-compassion', 108, 'Every day is a second chance.', 'Unknown'),
  ('c109', 'self-compassion', 109, 'Self-compassion is recognizing that the human experience is imperfect.', 'Kristin Neff'),
  ('c110', 'self-compassion', 110, 'Your best is good enough. Your enough is more than sufficient.', 'Unknown'),
  ('c111', 'self-compassion', 111, 'Just when the caterpillar thought the world was ending, he turned into a butterfly.', 'Barbara Haines Howett'),
  ('c112', 'self-compassion', 112, 'Be proud of how hard you are trying.', 'Unknown'),
  ('c113', 'self-compassion', 113, 'You have been assigned this mountain to show others it can be climbed.', 'Mel Robbins'),
  ('c114', 'self-compassion', 114, 'I am not perfect, but I am perfectly me.', 'Unknown'),
  ('c115', 'self-compassion', 115, 'The most important opinion of all is the one you have of yourself.', 'Unknown'),
  ('c116', 'self-compassion', 116, 'Start where you are. Use what you have. Do what you can.', 'Arthur Ashe'),
  ('c117', 'self-compassion', 117, 'If you are always trying to be normal, you will never know how amazing you can be.', 'Maya Angelou'),
  ('c118', 'self-compassion', 118, 'To thine own self be true.', 'William Shakespeare'),
  ('c119', 'self-compassion', 119, 'No amount of self-improvement can make up for any lack of self-acceptance.', 'Robert Holden'),
  ('c120', 'self-compassion', 120, 'You have survived 100% of your worst days.', 'Unknown'),
  ('c121', 'self-compassion', 121, 'There is no hate in the light, and love is the weapon of the brave.', 'Unknown'),
  ('c122', 'self-compassion', 122, 'The goal is progress, not perfection.', 'Unknown'),
  ('c123', 'self-compassion', 123, 'You are so used to your features, you don''t know how beautiful you look to a stranger.', 'Unknown'),
  ('c124', 'self-compassion', 124, 'Love is not something we give or get; it is something that we nurture and grow.', 'Brené Brown'),
  ('c125', 'self-compassion', 125, 'Be compassionate with yourself. Growth takes time.', 'Unknown'),
  ('c126', 'self-compassion', 126, 'You are whole. Not a puzzle with missing pieces, not a house with broken windows.', 'Unknown'),
  ('c127', 'self-compassion', 127, 'Self-love is the source of all our other loves.', 'Pierre Corneille'),
  ('c128', 'self-compassion', 128, 'Give yourself grace, especially on the hard days.', 'Unknown'),
  ('c129', 'self-compassion', 129, 'Your soul deserves the same tenderness you give to your most loved ones.', 'Unknown'),
  ('c130', 'self-compassion', 130, 'Honor yourself. You can''t do that if you spend your time being cruel to yourself.', 'Unknown'),
  ('c131', 'self-compassion', 131, 'The antidote for fifty enemies is one friend.', 'Aristotle (self-compassion tradition)'),
  ('c132', 'self-compassion', 132, 'Everything is a phase. Everything passes. Hold on.', 'Unknown'),
  ('c133', 'self-compassion', 133, 'Speak to yourself the way you would speak to someone worth saving.', 'Unknown'),
  ('c134', 'self-compassion', 134, 'Part of healing is learning to like yourself again.', 'Unknown'),
  ('c135', 'self-compassion', 135, 'It''s okay to rest without guilt.', 'Unknown'),
  ('c136', 'self-compassion', 136, 'I am not what I think I am. I am not what you think I am. I am what I think you think I am.', 'Charles H. Cooley (self-awareness tradition)'),
  ('c137', 'self-compassion', 137, 'Breathe. You are enough. You have enough. You do enough.', 'Unknown'),
  ('c138', 'self-compassion', 138, 'The key to happiness is letting each situation be what it is.', 'Mandy Hale'),
  ('c139', 'self-compassion', 139, 'Repair yourself with gold, like the Japanese art of kintsugi. Your cracks are your strength.', 'Unknown (kintsugi tradition)'),
  ('c140', 'self-compassion', 140, 'When we are no longer able to change a situation, we are challenged to change ourselves.', 'Viktor Frankl'),
  ('c141', 'self-compassion', 141, 'Today I will do what others won''t, so tomorrow I can do what others can''t.', 'Jerry Rice (self-compassion tradition)'),
  ('c142', 'self-compassion', 142, 'You don''t have to be perfect to be amazing.', 'Unknown'),
  ('c143', 'self-compassion', 143, 'Everything you need you already have.', 'Wayne Dyer'),
  ('c144', 'self-compassion', 144, 'Be gentle first with yourself if you wish to be gentle with others.', 'Lama Yeshe'),
  ('c145', 'self-compassion', 145, 'You owe yourself the love that you freely give to others.', 'Unknown'),
  ('c146', 'self-compassion', 146, 'No one can make you feel inferior without your consent.', 'Eleanor Roosevelt'),
  ('c147', 'self-compassion', 147, 'You are worthy of the life you imagine.', 'Unknown'),
  ('c148', 'self-compassion', 148, 'Dare to love yourself as if you were a rainbow with gold at both ends.', 'Aberjhani'),
  ('c149', 'self-compassion', 149, 'Come as you are. You are exactly where you need to be.', 'Unknown'),
  ('c150', 'self-compassion', 150, 'Love yourself enough to set boundaries.', 'Unknown'),
  ('c151', 'self-compassion', 151, 'Kindness to yourself is not selfish. It is necessary.', 'Unknown'),
  ('c152', 'self-compassion', 152, 'You deserve a standing ovation for staying alive this long.', 'Unknown'),
  ('c153', 'self-compassion', 153, 'To grow, you must be willing to let your present and future be totally unlike your past.', 'Alan Cohen'),
  ('c154', 'self-compassion', 154, 'I deeply and completely love and accept myself.', 'Louise L. Hay'),
  ('c155', 'self-compassion', 155, 'The wound is the place where the Light enters you.', 'Rumi'),
  ('c156', 'self-compassion', 156, 'You matter. Not in the way that makes headlines, but in ways that matter more.', 'Unknown'),
  ('c157', 'self-compassion', 157, 'Honor the space between no longer and not yet.', 'Nancy Levin'),
  ('c158', 'self-compassion', 158, 'Sometimes you have to pick yourself up and carry on.', 'Unknown'),
  ('c159', 'self-compassion', 159, 'There is no need to be perfect to inspire others. Let people get inspired by how you deal with imperfection.', 'Ziad K. Abdelnour'),
  ('c160', 'self-compassion', 160, 'Loving yourself is the greatest revolution.', 'Unknown'),
  ('c161', 'self-compassion', 161, 'What is inside you is stronger than anything that is outside of you.', 'Unknown'),
  ('c162', 'self-compassion', 162, 'Be kinder to yourself. And then let your kindness flood the world.', 'Pema Chödrön'),
  ('c163', 'self-compassion', 163, 'Your value doesn''t decrease based on someone''s inability to see your worth.', 'Unknown'),
  ('c164', 'self-compassion', 164, 'Just keep swimming.', 'Dory (Finding Nemo) — lighthearted self-compassion'),
  ('c165', 'self-compassion', 165, 'Imperfection is beauty, madness is genius, and it is better to be absolutely ridiculous than absolutely boring.', 'Marilyn Monroe'),
  ('c166', 'self-compassion', 166, 'You are allowed to rest.', 'Unknown'),
  ('c167', 'self-compassion', 167, 'The very fact that you worry about being a good person means you already are one.', 'Unknown'),
  ('c168', 'self-compassion', 168, 'Practice giving yourself the same compassion you would give a child in pain.', 'Kristin Neff'),
  ('c169', 'self-compassion', 169, 'You are not alone. Even when it feels that way.', 'Unknown'),
  ('c170', 'self-compassion', 170, 'Do not compare your inside to everyone else''s outside.', 'Unknown'),
  ('c171', 'self-compassion', 171, 'Not all storms come to disrupt your life, some come to clear your path.', 'Unknown'),
  ('c172', 'self-compassion', 172, 'Believe in yourself so much that even your insecurities feel inspired.', 'Unknown'),
  ('c173', 'self-compassion', 173, 'Self-kindness means refraining from judging and criticizing ourselves too harshly.', 'Kristin Neff'),
  ('c174', 'self-compassion', 174, 'Your life is your message to the world. Make sure it''s inspiring.', 'Lorrin L. Lee'),
  ('c175', 'self-compassion', 175, 'You are not your failures. You are still writing your story.', 'Unknown'),
  ('c176', 'self-compassion', 176, 'Sometimes being kind to yourself means saying no.', 'Unknown'),
  ('c177', 'self-compassion', 177, 'You are made of stardust and good intentions.', 'Unknown'),
  ('c178', 'self-compassion', 178, 'When you change the way you look at things, the things you look at change.', 'Wayne Dyer'),
  ('c179', 'self-compassion', 179, 'You deserve to take up space.', 'Unknown'),
  ('c180', 'self-compassion', 180, 'Let yourself shine. Don''t dim it for others.', 'Unknown'),
  ('c181', 'self-compassion', 181, 'Hold yourself to a standard of grace, not perfection.', 'Unknown'),
  ('c182', 'self-compassion', 182, 'We cannot change the cards we are dealt, just how we play the game.', 'Randy Pausch'),
  ('c183', 'self-compassion', 183, 'Be proud of your scars. They remind you that you healed.', 'Unknown'),
  ('c184', 'self-compassion', 184, 'To be human is to know pain and to accept it.', 'Unknown'),
  ('c185', 'self-compassion', 185, 'Softness is not weakness. It takes courage to stay delicate in a world this cruel.', 'Beau Taplin'),
  ('c186', 'self-compassion', 186, 'Compassion isn''t just about what you feel for others. It starts at home.', 'Unknown'),
  ('c187', 'self-compassion', 187, 'Celebrate every tiny victory.', 'Unknown'),
  ('c188', 'self-compassion', 188, 'You are enough just as you are. Each emotion you feel, everything in your life, everything you do or do not do — it is enough.', 'Haemin Sunim'),
  ('c189', 'self-compassion', 189, 'More smiling, less worrying. More compassion, less judgment. More blessed, less stressed.', 'Roy T. Bennett'),
  ('c190', 'self-compassion', 190, 'Remind yourself: I am whole. I am enough. I am worthy. I am loved.', 'Unknown'),
  ('c191', 'self-compassion', 191, 'Take care of your inner life.', 'Kathleen Norris'),
  ('c192', 'self-compassion', 192, 'Don''t let the opinions of others define you.', 'Unknown'),
  ('c193', 'self-compassion', 193, 'Fall in love with taking care of yourself.', 'Unknown'),
  ('c194', 'self-compassion', 194, 'Your job is not to be perfect. It is to be real.', 'Unknown'),
  ('c195', 'self-compassion', 195, 'Don''t push yourself to the point of breaking. Know your limits and honor them.', 'Unknown'),
  ('c196', 'self-compassion', 196, 'You are a priority, not an afterthought.', 'Unknown'),
  ('c197', 'self-compassion', 197, 'You are resilient. You have overcome everything life has put in your way.', 'Unknown'),
  ('c198', 'self-compassion', 198, 'Rest and self-care are so important. When you take time to replenish your spirit, it allows you to serve others from the overflow.', 'Eleanor Brown'),
  ('c199', 'self-compassion', 199, 'You are worth the quiet moment. You are worth the deeper breath.', 'Morgan Harper Nichols'),
  ('c200', 'self-compassion', 200, 'The thing that is really hard, and really amazing, is giving up on being perfect and beginning the work of becoming yourself.', 'Anna Quindlen'),
  ('h1', 'humor', 1, 'I''m on a whiskey diet. I''ve lost three days already.', 'Tommy Cooper'),
  ('h2', 'humor', 2, 'The best way to teach your kids about taxes is by eating 30% of their ice cream.', 'Bill Murray'),
  ('h3', 'humor', 3, 'I used to think I was indecisive, but now I''m not too sure.', 'Unknown'),
  ('h4', 'humor', 4, 'A day without sunshine is like, you know, night.', 'Steve Martin'),
  ('h5', 'humor', 5, 'I told my wife she was drawing her eyebrows too high. She looked surprised.', 'Unknown'),
  ('h6', 'humor', 6, 'Behind every great man is a woman rolling her eyes.', 'Jim Carrey'),
  ('h7', 'humor', 7, 'The road to success is dotted with many tempting parking spaces.', 'Will Rogers'),
  ('h8', 'humor', 8, 'I always wanted to be somebody, but now I realize I should have been more specific.', 'Lily Tomlin'),
  ('h9', 'humor', 9, 'People say nothing is impossible, but I do nothing every day.', 'A.A. Milne (Winnie the Pooh)'),
  ('h10', 'humor', 10, 'The trouble with having an open mind, of course, is that people will insist on coming along and trying to put things in it.', 'Terry Pratchett'),
  ('h11', 'humor', 11, 'Age is an issue of mind over matter. If you don''t mind, it doesn''t matter.', 'Mark Twain'),
  ('h12', 'humor', 12, 'I find television very educational. Every time someone turns it on, I go read a book.', 'Groucho Marx'),
  ('h13', 'humor', 13, 'I am so clever that sometimes I don''t understand a single word of what I am saying.', 'Oscar Wilde'),
  ('h14', 'humor', 14, 'You can''t have everything. Where would you put it?', 'Steven Wright'),
  ('h15', 'humor', 15, 'My doctor told me I had to stop throwing intimate dinner parties. There were too many forks in the road.', 'Unknown'),
  ('h16', 'humor', 16, 'I''m writing a book. I''ve got the page numbers done.', 'Steven Wright'),
  ('h17', 'humor', 17, 'When I was a boy the Dead Sea was only sick.', 'George Burns'),
  ('h18', 'humor', 18, 'I''m at the age where food has taken the place of sex in my life. In fact, I''ve just had a mirror put over my kitchen table.', 'Rodney Dangerfield'),
  ('h19', 'humor', 19, 'People who think they know everything are a great annoyance to those of us who do.', 'Isaac Asimov'),
  ('h20', 'humor', 20, 'Before you criticize someone, you should walk a mile in their shoes. That way, when you criticize them, you are a mile away and you have their shoes.', 'Jack Handey'),
  ('h21', 'humor', 21, 'Light travels faster than sound. This is why some people appear bright until they speak.', 'Unknown'),
  ('h22', 'humor', 22, 'The brain is a wonderful organ. It starts working the moment you get up in the morning and does not stop until you get into a meeting.', 'Robert Frost'),
  ('h23', 'humor', 23, 'Going to church doesn''t make you a Christian any more than standing in a garage makes you a car.', 'Billy Sunday'),
  ('h24', 'humor', 24, 'If you think you are too small to make a difference, try sleeping with a mosquito.', 'Dalai Lama'),
  ('h25', 'humor', 25, 'I haven''t spoken to my wife in years. I didn''t want to interrupt her.', 'Rodney Dangerfield'),
  ('h26', 'humor', 26, 'The secret of a happy marriage remains a secret.', 'Henny Youngman'),
  ('h27', 'humor', 27, 'Why do they call it rush hour when nothing moves?', 'Robin Williams'),
  ('h28', 'humor', 28, 'Age is of no importance unless you''re a cheese.', 'Billie Burke'),
  ('h29', 'humor', 29, 'I intend to live forever. So far, so good.', 'Steven Wright'),
  ('h30', 'humor', 30, 'Get your facts first, then you can distort them as you please.', 'Mark Twain'),
  ('h31', 'humor', 31, 'All right, everyone, line up alphabetically according to your height.', 'Casey Stengel'),
  ('h32', 'humor', 32, 'I''m not good at the advice. Can I interest you in a sarcastic comment?', 'Chandler Bing (Friends)'),
  ('h33', 'humor', 33, 'The key to eating healthy is avoiding any food that has a TV commercial.', 'Mike Birbiglia'),
  ('h34', 'humor', 34, 'If at first you don''t succeed, skydiving is not for you.', 'Unknown'),
  ('h35', 'humor', 35, 'Always borrow money from a pessimist. They won''t expect it back.', 'Oscar Wilde'),
  ('h36', 'humor', 36, 'Common sense is like deodorant. The people who need it most never use it.', 'Unknown'),
  ('h37', 'humor', 37, 'My therapist told me the way to achieve true inner peace is to finish what I start. So far I''ve finished two bags of M&Ms and a chocolate cake. I feel better already.', 'Dave Barry'),
