  ('h39', 'humor', 39, 'I used to be a banker, but I lost interest.', 'Unknown'),
  ('h40', 'humor', 40, 'A pessimist is someone who can look at the land of milk and honey and see only calories and cholesterol.', 'Unknown'),
  ('h41', 'humor', 41, 'If you''re too open-minded, your brains will fall out.', 'Lawrence Ferlinghetti'),
  ('h42', 'humor', 42, 'Wine is constant proof that God loves us and loves to see us happy.', 'Benjamin Franklin'),
  ('h43', 'humor', 43, 'The human brain is a wonderful thing. It starts the moment you are born and never stops, until you stand up to speak in public.', 'Unknown'),
