  ('h55', 'humor', 55, 'My mother always told me that if people make fun of you, it means they like you. She was a bully.', 'Unknown'),
  ('h56', 'humor', 56, 'The only mystery in life is why the kamikaze pilots wore helmets.', 'Al McGuire'),
  ('h57', 'humor', 57, 'Light travels faster than sound, which is why many people appear bright until they open their mouths.', 'Unknown'),
