  ('h79', 'humor', 79, 'Think left and think right and think low and think high. Oh, the thinks you can think up if only you try!', 'Dr. Seuss'),
  ('h80', 'humor', 80, 'A clear conscience is a sure sign of a bad memory.', 'Mark Twain'),
  ('h81', 'humor', 81, 'I used to sell furniture for a living. The trouble was, it was my own.', 'Les Dawson'),
  ('h82', 'humor', 82, 'There is no sunrise so beautiful that it is worth waking me up to see it.', 'Mindy Kaling'),
