  ('h84', 'humor', 84, 'The difference between genius and stupidity is that genius has its limits.', 'Albert Einstein'),
  ('h85', 'humor', 85, 'Outside of a dog, a book is man''s best friend. Inside a dog, it''s too dark to read.', 'Groucho Marx'),
  ('h86', 'humor', 86, 'A lot of people quit looking for work as soon as they find a job.', 'Zig Ziglar'),
  ('h87', 'humor', 87, 'I love deadlines. I like the whooshing sound they make as they fly by.', 'Douglas Adams'),
