  ('h110', 'humor', 110, 'Life is like a sewer — what you get out of it depends on what you put into it.', 'Tom Lehrer'),
  ('h111', 'humor', 111, 'The best way to lie is to tell the truth, carefully edited truth.', 'Unknown'),
  ('h112', 'humor', 112, 'By all means, let''s be open-minded, but not so open-minded that our brains drop out.', 'Richard Dawkins'),
  ('h113', 'humor', 113, 'You''re only given a little spark of madness. You mustn''t lose it.', 'Robin Williams'),
  ('h114', 'humor', 114, 'Never trust a skinny cook.', 'Unknown'),
  ('h115', 'humor', 115, 'The greatest pleasure in life is doing what people say you cannot do.', 'Walter Bagehot'),
  ('h116', 'humor', 116, 'If a book about failures doesn''t sell, is it a success?', 'Jerry Seinfeld'),
  ('h117', 'humor', 117, 'To steal ideas from one person is plagiarism. To steal from many is research.', 'Wilson Mizner'),
